using Microsoft.AspNetCore.Mvc; using Mubi.Api.DTOs.Base; using Mubi.Api.DTOs.Create; using Mubi.Api.DTOs.Update; using Mubi.Api.Services.Interfaces;
namespace Mubi.Api.Controllers;
[ApiController]
[Route("api/[controller]")]
public class UsuariosController : ControllerBase
{ private readonly IUsuarioService _service; public UsuariosController(IUsuarioService service){_service=service;} [HttpGet] public async Task<IActionResult> Get()=>Ok(await _service.GetAllAsync()); [HttpGet("{id:int}")] public async Task<IActionResult> GetById(int id){var data=await _service.GetByIdAsync(id); return data==null?NotFound():Ok(data);} [HttpPost] public async Task<IActionResult> Create(CreateUsuarioDto dto){var data=await _service.CreateAsync(dto); return CreatedAtAction(nameof(GetById), new { id = data.IdUsuario }, data);} [HttpPut("{id:int}")] public async Task<IActionResult> Update(int id, UpdateUsuarioDto dto){var data=await _service.UpdateAsync(id,dto); return data==null?NotFound():Ok(data);} [HttpDelete("{id:int}")] public async Task<IActionResult> Delete(int id){var ok=await _service.DeleteAsync(id); return ok?NoContent():NotFound();} [HttpPost("login")] public async Task<IActionResult> Login(LoginDto dto){var data=await _service.LoginAsync(dto); return data==null?Unauthorized(new{message="Credenciales inválidas."}):Ok(data);} }
